#include <stdlib.h>
#include <math.h>
#define MOD 1000000007

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        long long S = 1;
        for (int i = 0; i < N; i++) {
            long long x;
            scanf("%lld", &x);
            S = (S * x) % MOD;
        }
        long long i = 1;
        while (1) {
            long long cube = (i * i * i) % MOD;
            if (cube == 0) continue;
            long long gcd = __gcd(S, cube);
            if (gcd == 1) {
                printf("%lld\n", (i * S) % MOD);
                break;
            }
            i++;
        }
    }
    return 0;
}

